@Service
public class IndexAdminService {

    private final RestHighLevelClient client;
    private final ObjectMapper mapper;

    @Value("${elasticsearch.index.products:products}")
    private String productsIndex;

    @Value("${elasticsearch.index.queries:search_queries}")
    private String queriesIndex;

    public IndexAdminService(RestHighLevelClient client, ObjectMapper mapper) {
        this.client = client;
        this.mapper = mapper;
    }

    public void ensureIndices() throws IOException {
        ensureProductsIndex();
        ensureQueriesIndex();
    }

    public void recreateAll() throws IOException {
        deleteIndexIfExists(productsIndex);
        deleteIndexIfExists(queriesIndex);
        ensureIndices();
    }

    private void deleteIndexIfExists(String index) throws IOException {
        GetIndexRequest getIndexRequest = new GetIndexRequest(index);
        boolean exists = client.indices().exists(getIndexRequest, RequestOptions.DEFAULT);
        if (exists) {
            DeleteIndexRequest del = new DeleteIndexRequest(index);
            client.indices().delete(del, RequestOptions.DEFAULT);
        }
    }

    private void ensureProductsIndex() throws IOException {
        if (client.indices().exists(new GetIndexRequest(productsIndex), RequestOptions.DEFAULT)) return;

        CreateIndexRequest req = new CreateIndexRequest(productsIndex);
        req.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0)
                .put("analysis.analyzer.folded.type", "custom")
                .put("analysis.analyzer.folded.tokenizer", "standard")
                .putList("analysis.analyzer.folded.filter", "lowercase", "asciifolding")
        );

        Map<String, Object> props = new HashMap<>();
        props.put("id", field("keyword"));
        props.put("sku", field("keyword"));
        props.put("name", textFieldWithKeyword());
        props.put("description", textField());
        props.put("brand", keywordWithText());
        props.put("categories", field("keyword"));
        props.put("tags", field("keyword"));
        props.put("price", field("double"));
        props.put("currency", field("keyword"));
        props.put("inStock", field("boolean"));
        props.put("rating", field("float"));
        props.put("ratingCount", field("integer"));
        props.put("attributes", Map.of("type", "object", "dynamic", true));
        props.put("createdAt", field("date"));
        props.put("updatedAt", field("date"));

        Map<String, Object> mapping = Map.of(
                "dynamic", "true",
                "properties", props
        );
        req.mapping(toJson(mapping), XContentType.JSON);

        CreateIndexResponse resp = client.indices().create(req, RequestOptions.DEFAULT);
        if (!resp.isAcknowledged()) throw new ElasticsearchStatusException("Index not acknowledged: " + productsIndex, null);
    }

    private void ensureQueriesIndex() throws IOException {
        if (client.indices().exists(new GetIndexRequest(queriesIndex), RequestOptions.DEFAULT)) return;

        CreateIndexRequest req = new CreateIndexRequest(queriesIndex);
        req.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0)
        );

        Map<String, Object> props = new HashMap<>();
        props.put("query", textFieldWithKeyword());
        props.put("timestamp", field("date"));
        props.put("userId", field("keyword"));
        props.put("sessionId", field("keyword"));
        props.put("page", field("integer"));
        props.put("size", field("integer"));
        props.put("filters", Map.of("type", "object", "dynamic", true));
        props.put("totalHits", field("long"));
        props.put("tookMs", field("long"));

        Map<String, Object> mapping = Map.of(
                "dynamic", "true",
                "properties", props
        );
        req.mapping(toJson(mapping), XContentType.JSON);

        CreateIndexResponse resp = client.indices().create(req, RequestOptions.DEFAULT);
        if (!resp.isAcknowledged()) throw new ElasticsearchStatusException("Index not acknowledged: " + queriesIndex, null);
    }

    private Map<String, Object> field(String type) {
        return Map.of("type", type);
    }

    private Map<String, Object> textField() {
        return Map.of("type", "text", "analyzer", "folded");
    }

    private Map<String, Object> textFieldWithKeyword() {
        return Map.of(
                "type", "text",
                "analyzer", "folded",
                "fields", Map.of("keyword", Map.of("type", "keyword", "ignore_above", 256))
        );
    }

    private Map<String, Object> keywordWithText() {
        return Map.of(
                "type", "keyword",
                "fields", Map.of("text", Map.of("type", "text", "analyzer", "folded"))
        );
    }

    private String toJson(Object o) {
        try {
            return mapper.writeValueAsString(o);
        } catch (JsonProcessingException e) {
            throw new IllegalStateException(e);
        }
    }
}

package com.example.search.service;

import com.example.search.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.io.IOException;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import org.elasticsearch.action.DocWriteRequest;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.delete.DeleteRequest;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.get.GetRequest;
import org.elasticsearch.action.get.GetResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

@Service
public class ProductIndexService {

    private final RestHighLevelClient client;
    private final ObjectMapper mapper;

    @Value("${elasticsearch.index.products:products}")
    private String productsIndex;

    public ProductIndexService(RestHighLevelClient client, ObjectMapper mapper) {
        this.client = client;
        this.mapper = mapper;
    }

    public IndexResponse indexProduct(Product product) throws IOException {
        if (product.getCreatedAt() == null) product.setCreatedAt(Instant.now());
        product.setUpdatedAt(Instant.now());

        String id = product.getId() != null ? product.getId() : product.getSku();
        IndexRequest req = new IndexRequest(productsIndex)
                .id(id)
                .opType(DocWriteRequest.OpType.INDEX)
                .source(mapper.writeValueAsString(product), XContentType.JSON);

        return client.index(req, RequestOptions.DEFAULT);
    }

    public BulkResponse bulkIndex(List<Product> products) throws IOException {
        BulkRequest bulk = new BulkRequest();
        for (Product p : products) {
            if (p.getCreatedAt() == null) p.setCreatedAt(Instant.now());
            p.setUpdatedAt(Instant.now());
            String id = p.getId() != null ? p.getId() : p.getSku();
            bulk.add(new IndexRequest(productsIndex).id(id).source(mapper.writeValueAsString(p), XContentType.JSON));
        }
        return client.bulk(bulk, RequestOptions.DEFAULT);
    }

    public Product getById(String id) throws IOException {
        GetResponse resp = client.get(new GetRequest(productsIndex, id), RequestOptions.DEFAULT);
        if (!resp.isExists()) return null;
        Map<String, Object> src = resp.getSourceAsMap();
        return mapper.convertValue(src, Product.class);
    }

    public void deleteById(String id) throws IOException {
        client.delete(new DeleteRequest(productsIndex, id), RequestOptions.DEFAULT);
    }

    public List<Product> toProducts(List<Map<String, Object>> sources) {
        List<Product> out = new ArrayList<>();
        for (Map<String, Object> s : sources) out.add(mapper.convertValue(s, Product.class));
        return out;
    }
}

package com.example.search.service;

import com.example.search.dto.SearchRequestDto;
import com.example.search.dto.SearchResponseDto;
import com.example.search.model.Product;
import com.example.search.model.SearchQueryLog;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.io.IOException;
import java.time.Instant;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.Operator;
import org.elasticsearch.index.query.QueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.Aggregation;
import org.elasticsearch.search.aggregations.Aggregations;
import org.elasticsearch.search.aggregations.bucket.filter.FilterAggregationBuilder;
import org.elasticsearch.search.aggregations.bucket.filter.ParsedFilter;
import org.elasticsearch.search.aggregations.bucket.histogram.ParsedHistogram;
import org.elasticsearch.search.aggregations.bucket.histogram.ParsedDateHistogram;
import org.elasticsearch.search.aggregations.bucket.terms.ParsedStringTerms;
import org.elasticsearch.search.aggregations.bucket.terms.ParsedTerms;
import org.elasticsearch.search.aggregations.metrics.ParsedStats;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortBuilders;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

@Service
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper mapper;

    @Value("${elasticsearch.index.products:products}")
    private String productsIndex;

    @Value("${elasticsearch.index.queries:search_queries}")
    private String queriesIndex;

    public ProductSearchService(RestHighLevelClient client, ObjectMapper mapper) {
        this.client = client;
        this.mapper = mapper;
    }

    public SearchResponseDto<Product> search(SearchRequestDto req, String userId, String sessionId) throws IOException {
        int page = req.getPage() != null ? Math.max(0, req.getPage()) : 0;
        int size = req.getSize() != null ? Math.min(200, Math.max(1, req.getSize())) : 20;

        QueryBuilder baseQuery = buildQuery(req);
        BoolQueryBuilder filterWrap = QueryBuilders.boolQuery().must(baseQuery);
        applyFilters(filterWrap, req.getFilters());

        SearchSourceBuilder ssb = new SearchSourceBuilder()
                .query(filterWrap)
                .from(page * size)
                .size(size)
                .trackTotalHits(true);

        applySort(ssb, req.getSort());
        addFacets(ssb, req.getFacets());

        SearchRequest sreq = new SearchRequest(productsIndex).source(ssb);

        long start = System.currentTimeMillis();
        SearchResponse sresp = client.search(sreq, RequestOptions.DEFAULT);
        long tookMs = System.currentTimeMillis() - start;

        List<Product> items = new ArrayList<>();
        for (SearchHit hit : sresp.getHits().getHits()) {
            Map<String, Object> src = hit.getSourceAsMap();
            Product p = mapper.convertValue(src, Product.class);
            p.setId(hit.getId());
            items.add(p);
        }

        long total = sresp.getHits().getTotalHits() != null ? sresp.getHits().getTotalHits().value : items.size();
        Map<String, Object> facets = parseAggs(sresp.getAggregations());

        logQuery(req, userId, sessionId, total, tookMs);

        return new SearchResponseDto<>(total, tookMs, items, facets);
    }

    private QueryBuilder buildQuery(SearchRequestDto req) {
        String q = req.getQ();
        if (q == null || q.trim().isEmpty()) {
            return QueryBuilders.matchAllQuery();
        }
        MultiMatchQueryBuilder mm = QueryBuilders.multiMatchQuery(q.trim(),
                        "name^4",
                        "brand.text^2",
                        "categories^2",
                        "tags^2",
                        "description"
                )
                .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                .operator(Operator.AND)
                .fuzziness("AUTO");
        return mm;
    }

    @SuppressWarnings("unchecked")
    private void applyFilters(BoolQueryBuilder bq, Map<String, Object> filters) {
        if (filters == null || filters.isEmpty()) return;

        Object brand = filters.get("brand");
        if (brand instanceof String s && !s.isBlank()) {
            bq.filter(QueryBuilders.termQuery("brand", s));
        } else if (brand instanceof List<?> list && !list.isEmpty()) {
            bq.filter(QueryBuilders.termsQuery("brand", list));
        }

        Object categories = filters.get("categories");
        if (categories instanceof String s && !s.isBlank()) {
            bq.filter(QueryBuilders.termQuery("categories", s));
        } else if (categories instanceof List<?> list && !list.isEmpty()) {
            bq.filter(QueryBuilders.termsQuery("categories", list));
        }

        Object tags = filters.get("tags");
        if (tags instanceof String s && !s.isBlank()) {
            bq.filter(QueryBuilders.termQuery("tags", s));
        } else if (tags instanceof List<?> list && !list.isEmpty()) {
            bq.filter(QueryBuilders.termsQuery("tags", list));
        }

        Object inStock = filters.get("inStock");
        if (inStock instanceof Boolean b) {
            bq.filter(QueryBuilders.termQuery("inStock", b));
        }

        Object priceMin = filters.get("priceMin");
        Object priceMax = filters.get("priceMax");
        if (priceMin != null || priceMax != null) {
            var range = QueryBuilders.rangeQuery("price");
            if (priceMin != null) range.gte(priceMin);
            if (priceMax != null) range.lte(priceMax);
            bq.filter(range);
        }

        Object attrs = filters.get("attributes");
        if (attrs instanceof Map<?, ?> amap && !amap.isEmpty()) {
            for (Map.Entry<?, ?> e : amap.entrySet()) {
                String key = String.valueOf(e.getKey());
                Object val = e.getValue();
                if (val == null) continue;
                String field = "attributes." + key;
                if (val instanceof List<?> list && !list.isEmpty()) {
                    bq.filter(QueryBuilders.termsQuery(field, list));
                } else {
                    bq.filter(QueryBuilders.termQuery(field, val));
                }
            }
        }
    }

    private void applySort(SearchSourceBuilder ssb, String sort) {
        if (sort == null || sort.isBlank()) return;

        String s = sort.trim().toLowerCase();
        switch (s) {
            case "price_asc" -> ssb.sort(SortBuilders.fieldSort("price").order(SortOrder.ASC).missing("_last"));
            case "price_desc" -> ssb.sort(SortBuilders.fieldSort("price").order(SortOrder.DESC).missing("_last"));
            case "rating_desc" -> ssb.sort(SortBuilders.fieldSort("rating").order(SortOrder.DESC).missing("_last"));
            case "newest" -> ssb.sort(SortBuilders.fieldSort("createdAt").order(SortOrder.DESC).missing("_last"));
            default -> { }
        }
    }

    private void addFacets(SearchSourceBuilder ssb, List<String> facets) {
        List<String> f = facets != null && !facets.isEmpty()
                ? facets
                : List.of("brand", "categories", "tags", "price_stats");

        for (String facet : f) {
            if (facet == null) continue;
            switch (facet) {
                case "brand" -> ssb.aggregation(org.elasticsearch.search.aggregations.AggregationBuilders
                        .terms("facet_brand").field("brand").size(50));
                case "categories" -> ssb.aggregation(org.elasticsearch.search.aggregations.AggregationBuilders
                        .terms("facet_categories").field("categories").size(50));
                case "tags" -> ssb.aggregation(org.elasticsearch.search.aggregations.AggregationBuilders
                        .terms("facet_tags").field("tags").size(50));
                case "inStock" -> ssb.aggregation(org.elasticsearch.search.aggregations.AggregationBuilders
                        .terms("facet_inStock").field("inStock").size(10));
                case "price_stats" -> ssb.aggregation(org.elasticsearch.search.aggregations.AggregationBuilders
                        .stats("facet_price_stats").field("price"));
                default -> { }
            }
        }
    }

    private Map<String, Object> parseAggs(Aggregations aggs) {
        if (aggs == null) return Map.of();
        Map<String, Object> out = new LinkedHashMap<>();
        for (Aggregation a : aggs.asList()) {
            if (a instanceof ParsedStringTerms pst) {
                out.put(a.getName(), bucketsToMap(pst.getBuckets()));
            } else if (a instanceof ParsedTerms pt) {
                out.put(a.getName(), bucketsToMap(pt.getBuckets()));
            } else if (a instanceof ParsedStats ps) {
                Map<String, Object> m = new LinkedHashMap<>();
                m.put("count", ps.getCount());
                m.put("min", ps.getMin());
                m.put("max", ps.getMax());
                m.put("avg", ps.getAvg());
                m.put("sum", ps.getSum());
                out.put(a.getName(), m);
            } else if (a instanceof ParsedFilter pf) {
                out.put(a.getName(), Map.of("docCount", pf.getDocCount()));
            } else if (a instanceof ParsedDateHistogram pdh) {
                out.put(a.getName(), histogramToList(pdh));
            } else if (a instanceof ParsedHistogram ph) {
                out.put(a.getName(), histogramToList(ph));
            } else {
                out.put(a.getName(), Map.of("type", a.getType()));
            }
        }
        return out;
    }

    private List<Map<String, Object>> histogramToList(ParsedDateHistogram h) {
        List<Map<String, Object>> list = new ArrayList<>();
        for (var b : h.getBuckets()) {
            list.add(Map.of("key", b.getKeyAsString(), "docCount", b.getDocCount()));
        }
        return list;
    }

    private List<Map<String, Object>> histogramToList(ParsedHistogram h) {
        List<Map<String, Object>> list = new ArrayList<>();
        for (var b : h.getBuckets()) {
            list.add(Map.of("key", b.getKeyAsString(), "docCount", b.getDocCount()));
        }
        return list;
    }

    private List<Map<String, Object>> bucketsToMap(List<? extends org.elasticsearch.search.aggregations.bucket.MultiBucketsAggregation.Bucket> buckets) {
        List<Map<String, Object>> list = new ArrayList<>();
        for (var b : buckets) {
            list.add(Map.of("key", b.getKeyAsString(), "count", b.getDocCount()));
        }
        return list;
    }

    private void logQuery(SearchRequestDto req, String userId, String sessionId, long totalHits, long tookMs) {
        try {
            SearchQueryLog log = new SearchQueryLog();
            log.setId(UUID.randomUUID().toString());
            log.setQuery(req.getQ());
            log.setTimestamp(Instant.now());
            log.setUserId(userId);
            log.setSessionId(sessionId);
            log.setPage(req.getPage());
            log.setSize(req.getSize());
            log.setFilters(req.getFilters() != null ? new HashMap<>(req.getFilters()) : null);
            log.setTotalHits(totalHits);
            log.setTookMs(tookMs);

            IndexRequest ir = new IndexRequest(queriesIndex)
                    .id(log.getId())
                    .source(mapper.writeValueAsString(log), XContentType.JSON);

            client.index(ir, RequestOptions.DEFAULT);
        } catch (Exception ignored) {
        }
    }
}

package com.example.search.web;

import com.example.search.service.IndexAdminService;
import java.io.IOException;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/admin")
public class AdminController {

    private final IndexAdminService indexAdminService;

    public AdminController(IndexAdminService indexAdminService) {
        this.indexAdminService = indexAdminService;
    }

    @PostMapping("/indices/ensure")
    public ResponseEntity<?> ensure() throws IOException {
        indexAdminService.ensureIndices();
        return ResponseEntity.ok().build();
    }

    @PostMapping("/indices/recreate")
    public ResponseEntity<?> recreate() throws IOException {
        indexAdminService.recreateAll();
        return ResponseEntity.ok().build();
    }
}

package com.example.search.web;

import com.example.search.model.Product;
import com.example.search.service.ProductIndexService;
import java.io.IOException;
import java.util.List;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.index.IndexResponse;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductIndexService productIndexService;

    public ProductController(ProductIndexService productIndexService) {
        this.productIndexService = productIndexService;
    }

    @PutMapping("/{id}")
    public ResponseEntity<IndexResponse> index(@PathVariable String id, @RequestBody Product product) throws IOException {
        product.setId(id);
        return ResponseEntity.ok(productIndexService.indexProduct(product));
    }

    @PostMapping("/bulk")
    public ResponseEntity<BulkResponse> bulk(@RequestBody List<Product> products) throws IOException {
        return ResponseEntity.ok(productIndexService.bulkIndex(products));
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> get(@PathVariable String id) throws IOException {
        Product p = productIndexService.getById(id);
        if (p == null) return ResponseEntity.notFound().build();
        return ResponseEntity.ok(p);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<?> delete(@PathVariable String id) throws IOException {
        productIndexService.deleteById(id);
        return ResponseEntity.noContent().build();
    }
}

